const user = $input.item.json;
const webhookBody = $('Webhook').item.json.body;

// Check user exists
if (!user || !user.user_id) {
  return [
    {
      json: {
        _gate: 'BLOCK',
        status: 404,
        error: 'User not found.',
        code: 'USER_NOT_FOUND'
      }
    }
  ];
}

const allowedTiers = ['149', '299'];
const tierStr = String(user.plan_tier || '').replace(/[^0-9]/g, '');

if (!allowedTiers.includes(tierStr)) {
  return [
    {
      json: {
        _gate: 'BLOCK',
        status: 403,
        error: 'Automation Builder requires the Growth ($149) or Scale ($299) plan.',
        code: 'PLAN_UPGRADE_REQUIRED',
        current_tier: user.plan_tier || 'free',
        upgrade_url: 'https://nova-ops.space/upgrade',
        upsell_message: 'Unlock Automation Builder + 5 more power tools starting at $149/mo. Upgrade now at nova-ops.space/upgrade'
      }
    }
  ];
}

// Validate required body fields
const { user_id, process_description, integrations } = webhookBody;

if (!process_description || process_description.trim().length < 20) {
  return [
    {
      json: {
        _gate: 'BLOCK',
        status: 400,
        error: 'process_description must be at least 20 characters.',
        code: 'INVALID_INPUT'
      }
    }
  ];
}

const integrationsArr = Array.isArray(integrations) ? integrations : (integrations ? [integrations] : []);

return [
  {
    json: {
      _gate: 'PASS',
      user_id,
      plan_tier: tierStr,
      process_description: process_description.trim(),
      integrations: integrationsArr
    }
  }
];

const raw = $input.item.json;
const contextData = $('Build Claude Context').item.json;

// Extract text from Claude response
let contentText = '';
if (raw.content && Array.isArray(raw.content)) {
  contentText = raw.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Unexpected Claude response shape: ' + JSON.stringify(raw).substring(0, 200));
}

// Strip any accidental markdown fences
const cleaned = contentText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsedWorkflow;
let parseError = null;

try {
  parsedWorkflow = JSON.parse(cleaned);
} catch (e) {
  parseError = e.message;
}

// Validate it looks like an n8n workflow
const isValidWorkflow = (
  parsedWorkflow &&
  typeof parsedWorkflow === 'object' &&
  Array.isArray(parsedWorkflow.nodes) &&
  parsedWorkflow.nodes.length > 0 &&
  typeof parsedWorkflow.connections === 'object'
);

if (!isValidWorkflow) {
  // Signal retry needed
  return [
    {
      json: {
        _parse_status: 'FAILED',
        parse_error: parseError || 'Missing nodes or connections',
        raw_response: cleaned.substring(0, 800),
        user_id: contextData.user_id,
        process_description: contextData.process_description,
        integrations: contextData.integrations,
        system_prompt: contextData.system_prompt,
        n8n_reference: contextData.n8n_reference,
        attempt: contextData.attempt || 1
      }
    }
  ];
}

return [
  {
    json: {
      _parse_status: 'OK',
      user_id: contextData.user_id,
      process_description: contextData.process_description,
      workflow_json: parsedWorkflow,
      workflow_json_string: JSON.stringify(parsedWorkflow),
      node_count: parsedWorkflow.nodes.length
    }
  }
];

const raw = $input.item.json;
const previousData = $('Parse Failed?').item.json;

let contentText = '';
if (raw.content && Array.isArray(raw.content)) {
  contentText = raw.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Retry: Unexpected Claude response shape.');
}

const cleaned = contentText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsedWorkflow;
try {
  parsedWorkflow = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Retry attempt also failed to produce valid JSON. Parse error: ' + e.message + ' | Snippet: ' + cleaned.substring(0, 300));
}

const isValidWorkflow = (
  parsedWorkflow &&
  typeof parsedWorkflow === 'object' &&
  Array.isArray(parsedWorkflow.nodes) &&
  parsedWorkflow.nodes.length > 0 &&
  typeof parsedWorkflow.connections === 'object'
);

if (!isValidWorkflow) {
  throw new Error('Retry produced JSON but it is missing required n8n workflow fields (nodes, connections).');
}

return [
  {
    json: {
      _parse_status: 'OK',
      user_id: previousData.user_id,
      process_description: previousData.process_description,
      workflow_json: parsedWorkflow,
      workflow_json_string: JSON.stringify(parsedWorkflow),
      node_count: parsedWorkflow.nodes.length,
      was_retry: true
    }
  }
];

